import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.BYehg5q7.js";const c=JSON.parse('{"title":"Health Goals","description":"","frontmatter":{},"headers":[],"relativePath":"guide/health-goals.md","filePath":"guide/health-goals.md","lastUpdated":1771855656000}'),s={name:"guide/health-goals.md"};function l(i,e,n,h,d,g){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="health-goals" tabindex="-1">Health Goals <a class="header-anchor" href="#health-goals" aria-label="Permalink to &quot;Health Goals&quot;">​</a></h1><p>The Health Goals card lets you tell the AI what you are actually trying to achieve. Instead of generic interpretations, the AI prioritizes its analysis around the outcomes that matter most to you.</p><h2 id="setting-your-goals" tabindex="-1">Setting Your Goals <a class="header-anchor" href="#setting-your-goals" aria-label="Permalink to &quot;Setting Your Goals&quot;">​</a></h2><p>Click the <strong>Health Goals</strong> card on the dashboard to open the editor. In the editor you can:</p><ul><li>Add a new goal by typing it in the text field and clicking <strong>Add</strong></li><li>Assign each goal a severity level: <strong>Major</strong>, <strong>Mild</strong>, or <strong>Minor</strong></li><li>Delete goals you no longer need</li></ul><p>There is no limit to the number of goals you can add.</p><h2 id="severity-levels" tabindex="-1">Severity Levels <a class="header-anchor" href="#severity-levels" aria-label="Permalink to &quot;Severity Levels&quot;">​</a></h2><p>Severity tells the AI how much weight to give each goal:</p><table tabindex="0"><thead><tr><th>Level</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Major</strong></td><td>Top priority — the AI addresses these first in every analysis</td></tr><tr><td><strong>Mild</strong></td><td>Important, but secondary to major goals</td></tr><tr><td><strong>Minor</strong></td><td>Background context the AI keeps in mind</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Be specific. &quot;Reduce LDL below 3.0 mmol/L&quot; gives the AI more to work with than &quot;improve cholesterol.&quot; Specific goals lead to more targeted insights.</p></div><h2 id="dashboard-display" tabindex="-1">Dashboard Display <a class="header-anchor" href="#dashboard-display" aria-label="Permalink to &quot;Dashboard Display&quot;">​</a></h2><p>The Health Goals card on the dashboard shows your first three goals at a glance, with a severity badge next to each one. If you have more than three goals, open the editor to see them all.</p><p>If you have not set any goals yet, the card shows a placeholder prompt to get you started.</p><h2 id="how-goals-shape-ai-responses" tabindex="-1">How Goals Shape AI Responses <a class="header-anchor" href="#how-goals-shape-ai-responses" aria-label="Permalink to &quot;How Goals Shape AI Responses&quot;">​</a></h2><p>When you send a message in the AI chat, your goals are included in the context — grouped by severity, major first. The AI will naturally weave your goals into its analysis: flagging markers that are moving in the right direction, noting where you are off track, and suggesting what to watch next.</p><p>Goals are also included in the AI&#39;s reasoning for the <a href="/docs/guide/focus-card.html">Focus Card</a> and for per-marker explanations in the detail view.</p><h2 id="export-and-import" tabindex="-1">Export and Import <a class="header-anchor" href="#export-and-import" aria-label="Permalink to &quot;Export and Import&quot;">​</a></h2><p>Health Goals are included in your JSON export. When you import a file, goals are merged by content — duplicates are automatically removed.</p>',18)])])}const u=t(s,[["render",l]]);export{c as __pageData,u as default};
